async def seed_faq():
    async with engine.begin() as conn:
        await conn.run_sync(Base.metadata.create_all)
    async with AsyncSessionLocal() as db:
        for country_slug, faq_list in ALL_FAQS:
            for i, (q, a) in enumerate(faq_list):
                exists = (await db.execute(
                    select(FAQ).where(FAQ.country_slug == country_slug, FAQ.order == i)
                )).scalar_one_or_none()
                if not exists:
                    db.add(FAQ(country_slug=country_slug, question=q, answer=a, order=i))
            print(f"✅ FAQ: {country_slug} ({len(faq_list)} items)")

        # Generic FAQs for remaining countries
        for slug in ["be", "ch", "at", "pl", "cz", "se", "no", "fi"]:
            for i, (q, a) in enumerate(GENERIC_FAQ):
                exists = (await db.execute(
                    select(FAQ).where(FAQ.country_slug == slug, FAQ.order == i)
                )).scalar_one_or_none()
                if not exists:
                    db.add(FAQ(country_slug=slug, question=q, answer=a, order=i))
            print(f"✅ FAQ: {slug} (generic, {len(GENERIC_FAQ)} items)")

        await db.commit()
    print("❓ FAQs seeded!")

if __name__ == "__main__":
    asyncio.run(seed_faq())
